import{_ as e,o as n,c as a,af as o}from"./chunks/framework.BSym9njW.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01-deploy/minicpm-o/minicpm-o-model.md","filePath":"en/01-deploy/minicpm-o/minicpm-o-model.md","lastUpdated":1782376800000}'),i={name:"01-deploy/minicpm-o/minicpm-o-model.md"};function r(s,t,d,l,p,c){return n(),a("div",null,[...t[0]||(t[0]=[o(`<h2 id="minicpm-o-4-5-model-introduction" tabindex="-1">MiniCPM-o 4.5 Model Introduction <a class="header-anchor" href="#minicpm-o-4-5-model-introduction" aria-label="Permalink to &quot;MiniCPM-o 4.5 Model Introduction&quot;">​</a></h2><p>This page introduces the <strong>MiniCPM-o 4.5</strong> omni-modal architecture, sub-model breakdown, and GGUF file checklist to help you prepare before deployment.</p><blockquote><p>Prerequisite: Recommended to complete <a href="/hello-rocm/00-environment/">ROCm Environment Setup</a> first.</p></blockquote><hr><h3 id="_1-what-is-minicpm-o" tabindex="-1">1. What is MiniCPM-o <a class="header-anchor" href="#_1-what-is-minicpm-o" aria-label="Permalink to &quot;1. What is MiniCPM-o&quot;">​</a></h3><p>MiniCPM-o (Omni) is an end-to-end omni-modal model series from OpenBMB. Version 4.5 has approximately <strong>9B total parameters</strong>, composed of four backbone modules:</p><table tabindex="0"><thead><tr><th>Backbone Module</th><th>Base Model</th></tr></thead><tbody><tr><td>LLM backbone</td><td><strong>Qwen3-8B</strong></td></tr><tr><td>Vision encoder</td><td><strong>SigLIP2</strong></td></tr><tr><td>Audio encoder</td><td><strong>Whisper-medium</strong></td></tr><tr><td>Speech synthesis (TTS)</td><td><strong>CosyVoice2</strong></td></tr></tbody></table><blockquote><p>The model is <strong>built in an end-to-end fashion</strong> — the modality encoders/decoders and LLM are densely connected via hidden states, enabling better information flow and control, and facilitating full exploitation of rich multimodal knowledge during training.</p></blockquote><p>Based on this architecture, MiniCPM-o 4.5 integrates the following capabilities:</p><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td><strong>Text chat</strong></td><td>Same as a regular LLM, supports multi-turn conversation and system prompts, 30+ languages</td></tr><tr><td><strong>Voice input</strong></td><td>Real-time audio stream encoding, understands spoken input (bilingual real-time speech in Chinese &amp; English)</td></tr><tr><td><strong>Image / Video understanding</strong></td><td>High-resolution images (up to 1.8M pixels) and high-FPS video understanding (up to 10fps)</td></tr><tr><td><strong>Voice output (TTS)</strong></td><td>Natural speech synthesis, supports voice cloning, emotion control, and long speech generation (&gt;1 min)</td></tr><tr><td><strong>Full-duplex conversation</strong></td><td>Simultaneously listens to the microphone and generates voice responses, input and output streams do not block each other</td></tr><tr><td><strong>Proactive interaction</strong></td><td>Monitors input streams at ~1Hz frequency, can initiate unprompted responses based on continuous scene understanding</td></tr></tbody></table><p>Compared to a pure text model of the same parameter count, MiniCPM-o 4.5 achieves a full-duplex response latency of approximately <strong>800 ms</strong>, enabling near-real-time voice interaction on edge devices.</p><hr><h3 id="_2-model-architecture" tabindex="-1">2. Model Architecture <a class="header-anchor" href="#_2-model-architecture" aria-label="Permalink to &quot;2. Model Architecture&quot;">​</a></h3><p>MiniCPM-o 4.5 consists of multiple independent modules, each loaded as a separate GGUF file by <code>llama.cpp-omni</code>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>MiniCPM-o 4.5 (full omni inference)</span></span>
<span class="line"><span>├── LLM (Qwen3-8B)             MiniCPM-o-4_5-Q4_K_M.gguf             ~4.9 GB</span></span>
<span class="line"><span>├── Vision encoder (SigLIP2)    vision/MiniCPM-o-4_5-vision-F16.gguf  ~0.9 GB</span></span>
<span class="line"><span>├── Audio encoder               audio/MiniCPM-o-4_5-audio-F16.gguf ~1.2 GB</span></span>
<span class="line"><span>├── TTS language model          tts/MiniCPM-o-4_5-tts-F16.gguf   ~0.5 GB</span></span>
<span class="line"><span>├── TTS projector               tts/MiniCPM-o-4_5-projector-F16.gguf  ~0.1 GB</span></span>
<span class="line"><span>└── Token-to-Wav (vocoder)</span></span>
<span class="line"><span>    ├── token2wav-gguf/encoder.gguf</span></span>
<span class="line"><span>    ├── token2wav-gguf/flow_matching.gguf</span></span>
<span class="line"><span>    ├── token2wav-gguf/flow_extra.gguf</span></span>
<span class="line"><span>    ├── token2wav-gguf/hifigan2.gguf</span></span>
<span class="line"><span>    └── token2wav-gguf/prompt_cache.gguf    total ~0.7 GB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>All 10 GGUF files total approximately 8.3 GB</strong> (Q4_K_M quantization).</p><hr><h3 id="_3-available-versions-and-quantization" tabindex="-1">3. Available Versions and Quantization <a class="header-anchor" href="#_3-available-versions-and-quantization" aria-label="Permalink to &quot;3. Available Versions and Quantization&quot;">​</a></h3><p>This tutorial uses <strong>Q4_K_M quantization</strong> for the LLM backbone, which balances precision and VRAM usage well for consumer AMD GPUs and APUs.</p><table tabindex="0"><thead><tr><th>File</th><th>Quantization</th><th>Purpose</th></tr></thead><tbody><tr><td><code>MiniCPM-o-4_5-Q4_K_M.gguf</code></td><td>Q4_K_M</td><td>LLM backbone (text generation)</td></tr><tr><td><code>vision/MiniCPM-o-4_5-vision-F16.gguf</code></td><td>F16</td><td>Image understanding</td></tr><tr><td><code>audio/MiniCPM-o-4_5-audio-F16.gguf</code></td><td>F16</td><td>Audio input understanding</td></tr><tr><td><code>tts/MiniCPM-o-4_5-tts-F16.gguf</code></td><td>F16</td><td>Speech synthesis (LM part)</td></tr><tr><td><code>tts/MiniCPM-o-4_5-projector-F16.gguf</code></td><td>F16</td><td>Speech synthesis (projection)</td></tr><tr><td><code>token2wav-gguf/*.gguf</code> (5 files)</td><td>—</td><td>Vocoder (audio waveform generation)</td></tr></tbody></table><blockquote><p>Sub-models (vision, audio, TTS) are currently only available in F16. Even with Q4 quantization on the LLM backbone, total VRAM usage remains ~8.3 GB. Future Q8/Q4 sub-model variants may reduce this further.</p></blockquote><hr><h3 id="_4-vram-estimation" tabindex="-1">4. VRAM Estimation <a class="header-anchor" href="#_4-vram-estimation" aria-label="Permalink to &quot;4. VRAM Estimation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Modules loaded</th><th>Approx. VRAM</th></tr></thead><tbody><tr><td>Text only</td><td>LLM</td><td>~5 GB</td></tr><tr><td>Text + image</td><td>LLM + vision encoder</td><td>~6 GB</td></tr><tr><td>Text + voice input</td><td>LLM + audio encoder</td><td>~6.5 GB</td></tr><tr><td>Full omni (voice in + TTS out)</td><td>LLM + vision + audio + TTS + Token2Wav</td><td><strong>~9 GB</strong></td></tr></tbody></table><blockquote><p><strong>Note</strong>: Estimates assume a 4096-token context. Using an 8192-token context adds ~1–2 GB for KV cache.</p><p>AMD Ryzen AI MAX+ 395 APUs with 64 GB unified memory (all usable as VRAM) can comfortably run all modules with room for large contexts.</p></blockquote><hr><h3 id="_5-conversation-modes" tabindex="-1">5. Conversation Modes <a class="header-anchor" href="#_5-conversation-modes" aria-label="Permalink to &quot;5. Conversation Modes&quot;">​</a></h3><p>Both <code>llama.cpp-omni</code> and MiniCPM-o-Demo support 4 conversation modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Input</th><th>Output</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Turn-based</strong></td><td>Audio file / text</td><td>Text + TTS</td><td>Most stable; good for initial validation</td></tr><tr><td><strong>Half-Duplex</strong></td><td>Live microphone</td><td>Text + TTS</td><td>Speaks after user finishes; no interruption</td></tr><tr><td><strong>Omni (full-duplex)</strong></td><td>Live mic + camera</td><td>Real-time audio stream</td><td>Simultaneous listen + speak with interruption</td></tr><tr><td><strong>Audio Duplex</strong></td><td>Live microphone</td><td>Real-time audio stream</td><td>Same as Omni but camera not required</td></tr></tbody></table><p>CLI deployment (<code>llama-omni-cli</code>) is suited to validating Turn-based mode. The Web Demo supports all 4 modes, enabling real Omni full-duplex via a browser with camera and microphone.</p><hr><h3 id="_6-where-to-download-models" tabindex="-1">6. Where to Download Models <a class="header-anchor" href="#_6-where-to-download-models" aria-label="Permalink to &quot;6. Where to Download Models&quot;">​</a></h3><p>GGUF files are available from <strong>ModelScope</strong> (recommended for mainland China, faster download) or <strong>Hugging Face</strong>:</p><table tabindex="0"><thead><tr><th>Source</th><th>URL</th></tr></thead><tbody><tr><td>Hugging Face</td><td><a href="https://huggingface.co/OpenBMB/MiniCPM-o-4_5-gguf" target="_blank" rel="noreferrer">OpenBMB/MiniCPM-o-4_5-gguf</a></td></tr><tr><td>ModelScope</td><td><a href="https://www.modelscope.cn/models/OpenBMB/MiniCPM-o-4_5-gguf" target="_blank" rel="noreferrer">OpenBMB/MiniCPM-o-4_5-gguf</a></td></tr></tbody></table><hr><h3 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h3><ul><li><a href="https://github.com/OpenBMB/MiniCPM-o" target="_blank" rel="noreferrer">MiniCPM-o Official Repository</a></li><li><a href="https://arxiv.org/abs/2408.01800" target="_blank" rel="noreferrer">MiniCPM-o Technical Report (arxiv)</a></li><li><a href="https://github.com/tc-mb/llama.cpp-omni" target="_blank" rel="noreferrer">llama.cpp-omni</a></li></ul><hr><blockquote><p>After reading about the model architecture, proceed to <a href="./llamacpp-omni-rocm7-deploy">llama.cpp-omni CLI Deployment</a> or <a href="./webdemo-rocm7-deploy">Web Demo Full-Duplex Deployment</a>.</p></blockquote>`,39)])])}const h=e(i,[["render",r]]);export{m as __pageData,h as default};
